function commonSet(a, b) {
  return [...new Set(a)].filter(x => b.includes(x));
}

function commonMap(a, b) {
  const countA = new Map(a.map(x => [x, 0]).flatMap(([k]) => [k, (countA.get(k) || 0) + 1]));
  return b.filter(x => countA.get(x) > 0);
}

function commonTyped(a, b) {
  const sortedA = new Int32Array(a).sort();
  const sortedB = new Int32Array(b).sort();
  const result = [];
  let i = 0, j = 0;
  while (i < sortedA.length && j < sortedB.length) {
    if (sortedA[i] === sortedB[j]) {
      result.push(sortedA[i++]);
      j++;
    } else if (sortedA[i] < sortedB[j]) i++;
    else j++;
  }
  return result;
}
